settings.customCss:
@import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=Inter:wght@300;400;500;600;700&display=swap');
.mfp.mfp-bulgaria{--bg-parch:#f5f0e8;--bg-surface:#fff;--bg-dark:#1a1410;--bg-rose:#c94f6d;--bg-rose-soft:#fdf0f3;--bg-green:#2d5a3d;--bg-green-soft:#edf6f0;--bg-gold:#c8853a;--bg-gold-soft:#fdf4ec;--bg-muted:#7c6e62;--bg-border:#e6ddd2;--bg-line:#ded3c7;font-family:'Inter',system-ui,-apple-system,'Segoe UI',sans-serif;color:var(--bg-dark);background:var(--bg-parch);width:100%!important;max-width:760px!important;margin:0 auto!important;padding:0!important;box-sizing:border-box;overflow:visible!important}
.mfp-bulgaria,.mfp-bulgaria *{box-sizing:border-box}
.mfp-bulgaria .bg-card{overflow:visible;border:1px solid var(--bg-border);border-radius:24px;background:var(--bg-surface);box-shadow:0 24px 48px rgba(26,20,16,.16)}
.mfp-bulgaria .bg-border{height:16px;background:repeating-linear-gradient(90deg,rgba(201,79,109,.72) 0 12px,rgba(200,133,58,.65) 12px 16px,rgba(45,90,61,.68) 16px 24px,rgba(200,133,58,.45) 24px 28px);mask-image:linear-gradient(90deg,transparent,#000 6%,#000 94%,transparent)}
.mfp-bulgaria .bg-hero{position:relative;height:288px;overflow:hidden;border-radius:23px 23px 0 0;background:linear-gradient(135deg,#2d5a3d,#c94f6d)}
.mfp-bulgaria .bg-hero>img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;display:block}
.mfp-bulgaria .bg-hero-shade{position:absolute;inset:0;background:linear-gradient(90deg,rgba(26,20,16,.84),rgba(26,20,16,.45) 58%,rgba(26,20,16,.12))}
.mfp-bulgaria .bg-hero-copy{position:absolute;inset:0;display:flex;flex-direction:column;justify-content:center;padding:32px 48px;color:#fff}
.mfp-bulgaria .bg-hero-copy p{margin:0 0 8px;color:var(--bg-gold);font-size:12px;line-height:18px;font-weight:700;text-transform:uppercase;letter-spacing:.34em}
.mfp-bulgaria .bg-hero-copy h1{font-family:'DM Serif Display',Georgia,serif;margin:0;color:#fff;font-size:56px;line-height:.95;font-weight:400;letter-spacing:0;text-shadow:0 2px 22px rgba(0,0,0,.42)}
.mfp-bulgaria .bg-hero-copy span{display:block;max-width:360px;margin-top:14px;color:rgba(245,240,232,.9);font-size:15px;line-height:24px;font-weight:400}
.mfp-bulgaria .bg-thumb{position:absolute;right:22px;bottom:18px;width:176px;height:112px;margin:0;overflow:hidden;border:2px solid rgba(255,255,255,.28);border-radius:14px;box-shadow:0 18px 28px rgba(0,0,0,.25)}
.mfp-bulgaria .bg-thumb img{width:100%;height:100%;object-fit:cover;display:block}
.mfp-bulgaria .bg-thumb figcaption{position:absolute;left:0;right:0;bottom:0;background:rgba(26,20,16,.68);color:#fff;text-align:center;font-size:12px;line-height:22px}
.mfp-bulgaria .bg-body{padding:32px 40px 36px;background:var(--bg-surface)!important;color:var(--bg-dark)!important}
.mfp-bulgaria .bg-stepper{display:flex;align-items:flex-start;justify-content:center;margin-bottom:18px}
.mfp-bulgaria .bg-step{display:flex;flex-direction:column;align-items:center;text-align:center;min-width:76px}
.mfp-bulgaria .bg-step b{display:flex;align-items:center;justify-content:center;width:38px;height:38px;border:2px solid var(--bg-line);border-radius:999px;background:var(--bg-parch);color:var(--bg-muted);font-size:12px;line-height:1;font-weight:700}
.mfp-bulgaria .bg-step span{margin-top:6px;color:var(--bg-muted);font-size:12px;line-height:16px;font-weight:700}
.mfp-bulgaria .bg-step em{color:var(--bg-muted);font-size:11px;line-height:14px;font-style:normal}
.mfp-bulgaria .bg-step.is-active b{border-color:var(--bg-rose);background:#fff;color:var(--bg-rose)}
.mfp-bulgaria .bg-step.is-done b{border-color:var(--bg-rose);background:var(--bg-rose);color:#fff;font-size:0}
.mfp-bulgaria .bg-step.is-done b:after{content:'\2713';font-size:16px}
.mfp-bulgaria .bg-step.is-active span,.mfp-bulgaria .bg-step.is-done span{color:var(--bg-dark)}
.mfp-bulgaria .bg-line{display:block;width:52px;height:2px;margin:18px 6px 0;background:var(--bg-line)}
.mfp-bulgaria .bg-line.is-done{background:var(--bg-rose)}
.mfp-bulgaria .bg-folk{height:16px;margin:0 0 22px;background:linear-gradient(90deg,transparent,rgba(212,201,186,.95),transparent);position:relative}
.mfp-bulgaria .bg-folk:after{content:'';position:absolute;left:50%;top:50%;width:9px;height:9px;background:var(--bg-rose);transform:translate(-50%,-50%) rotate(45deg);box-shadow:-15px 0 0 rgba(201,79,109,.24),15px 0 0 rgba(201,79,109,.24)}
.mfp-bulgaria .bg-folk-green:after{background:var(--bg-green);box-shadow:-15px 0 0 rgba(45,90,61,.22),15px 0 0 rgba(45,90,61,.22)}
.mfp-bulgaria .bg-page{display:none}
.mfp-bulgaria .bg-page.is-active{display:block}
.mfp-bulgaria h2{font-family:'DM Serif Display',Georgia,serif;margin:0;color:var(--bg-dark);font-size:24px;line-height:32px;font-weight:400;letter-spacing:0}
.mfp-bulgaria .bg-mt{margin-top:18px}
.mfp-bulgaria .bg-grid{display:grid;gap:16px}
.mfp-bulgaria .bg-grid-2{grid-template-columns:repeat(2,minmax(0,1fr))}
.mfp-bulgaria .bg-field{display:block;margin-bottom:0}
.mfp-bulgaria .bg-field>span{display:block;margin:0 0 8px;color:var(--bg-muted);font-size:12px;line-height:18px;font-weight:700;text-transform:uppercase;letter-spacing:.16em}
.mfp-bulgaria .bg-field small{display:block;margin-top:5px;text-align:right;color:var(--bg-muted);font-size:12px}
.mfp-bulgaria .mf-row{display:grid!important;grid-template-columns:repeat(2,minmax(0,1fr))!important;gap:16px!important;width:100%!important}
.mfp-bulgaria .mf-row .mf-field-group{margin:0!important}
.mfp-bulgaria .mf-field-label{display:none!important}
.mfp-bulgaria .mf-row .mf-field-label{display:block!important;margin:0 0 8px!important;color:var(--bg-muted)!important;font-size:12px!important;line-height:18px!important;font-weight:700!important;text-transform:uppercase!important;letter-spacing:.16em!important}
.mfp-bulgaria .mf-field-group{margin:0!important;width:100%!important}
.mfp-bulgaria .mf-input,.mfp-bulgaria .mf-select,.mfp-bulgaria .mf-textarea,.mfp-bulgaria input[type='date']{width:100%!important;min-height:46px!important;border:1px solid var(--bg-border)!important;border-radius:8px!important;background:#fbfaf7!important;color:var(--bg-dark)!important;padding:10px 14px!important;font-family:'Inter',system-ui,sans-serif!important;font-size:15px!important;line-height:22px!important;box-shadow:none!important;outline:0!important;transition:border-color .15s ease,box-shadow .15s ease!important}
.mfp-bulgaria .mf-textarea{min-height:116px!important;height:auto!important;resize:vertical}
.mfp-bulgaria .mf-input::placeholder,.mfp-bulgaria .mf-textarea::placeholder{color:#a9998c!important;opacity:1}
.mfp-bulgaria .mf-input:focus,.mfp-bulgaria .mf-select:focus,.mfp-bulgaria .mf-textarea:focus{border-color:var(--bg-rose)!important;box-shadow:0 0 0 2px rgba(201,79,109,.1)!important}
.mfp-bulgaria .mf-select{appearance:none!important;-webkit-appearance:none!important;padding-right:38px!important}
.mfp-bulgaria .bg-date-field{position:relative!important;z-index:40!important}
.mfp-bulgaria .bg-date-field .mf-cal,.mfp-bulgaria .bg-date-field .mf-date-input-wrap{position:relative!important;overflow:visible!important}
.mfp-bulgaria .bg-date-field .mf-cal-panel{z-index:10000!important}
.mfp-bulgaria .mf-date-picker,.mfp-bulgaria .mf-datepicker,.mfp-bulgaria .flatpickr-calendar,.mfp-bulgaria .react-datepicker,.mfp-bulgaria [data-datepicker],.mfp-bulgaria .rdp{z-index:9999!important}
.mfp-bulgaria .mf-field-error{margin-top:5px;color:#b91c1c;font-size:12px;line-height:16px}
.mfp-bulgaria .mf-option-group--chips{display:flex!important;flex-wrap:wrap!important;align-items:flex-start!important;justify-content:flex-start!important;gap:8px!important}
.mfp-bulgaria .mf-option-group--chips .mf-option-item{display:inline-flex!important;width:auto!important;max-width:100%!important;flex:0 1 auto!important;margin:0!important;padding:0!important;background:transparent!important;border:0!important;box-shadow:none!important}
.mfp-bulgaria .mf-option-group--chips .mf-option-control,.mfp-bulgaria .mf-option-group--cards .mf-option-control{position:absolute!important;opacity:0!important;width:1px!important;height:1px!important;overflow:hidden!important;pointer-events:none!important;clip-path:inset(50%)!important}
.mfp-bulgaria .mf-option-group--chips .mf-option-ui{display:inline-flex!important;align-items:center!important;justify-content:center!important;width:auto!important;min-height:31px!important;padding:6px 14px!important;border:1px solid color-mix(in oklab,var(--bg-border) 64%,var(--bg-rose) 36%)!important;border-radius:999px!important;background:#fff!important;color:var(--bg-muted)!important;box-shadow:0 1px 2px rgba(26,20,16,.04)!important;transition:all .16s ease!important}
.mfp-bulgaria .mf-option-group--chips .mf-option-label{color:inherit!important;font-size:13px!important;line-height:17px!important;font-weight:600!important;white-space:normal!important}
.mfp-bulgaria .mf-option-group--chips .mf-option-item:hover .mf-option-ui{border-color:var(--bg-rose)!important;background:var(--bg-rose-soft)!important;transform:translateY(-1px)!important}
.mfp-bulgaria .mf-option-group--chips .mf-option-control:checked+.mf-option-ui{border-color:var(--bg-rose)!important;background:var(--bg-rose)!important;color:#fff!important;box-shadow:0 8px 20px rgba(201,79,109,.22)!important}
.mfp-bulgaria .mf-option-group--cards{display:grid!important;grid-template-columns:repeat(2,minmax(0,1fr))!important;gap:12px!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-item{display:block!important;width:100%!important;margin:0!important;padding:0!important;cursor:pointer}
.mfp-bulgaria .mf-option-group--cards .mf-option-ui{position:relative!important;display:flex!important;align-items:flex-start!important;gap:12px!important;width:100%!important;min-height:88px!important;padding:14px 38px 14px 14px!important;border:1px solid var(--bg-border)!important;border-radius:14px!important;background:#fbfaf7!important;color:var(--bg-dark)!important;box-shadow:none!important;transition:all .16s ease!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-item:hover .mf-option-ui{border-color:var(--bg-rose)!important;background:var(--bg-rose-soft)!important;transform:translateY(-1px)}
.mfp-bulgaria .mf-option-group--cards .mf-option-control:checked+.mf-option-ui{border-color:var(--bg-rose)!important;background:var(--bg-rose-soft)!important;box-shadow:0 0 0 1px var(--bg-rose),0 12px 24px rgba(201,79,109,.14)!important}
.mfp-bulgaria .bg-region-field .mf-option-group--cards .mf-option-control:checked+.mf-option-ui{border-color:var(--bg-green)!important;background:var(--bg-green-soft)!important;box-shadow:0 0 0 1px var(--bg-green),0 12px 24px rgba(45,90,61,.14)!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-icon{display:flex!important;align-items:center!important;justify-content:center;width:34px!important;height:34px!important;flex:0 0 34px!important;border-radius:10px!important;background:#fff!important;color:var(--bg-rose)!important;font-size:18px!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-control:checked+.mf-option-ui .mf-option-icon{background:var(--bg-rose)!important;color:#fff!important}
.mfp-bulgaria .bg-region-field .mf-option-group--cards .mf-option-control:checked+.mf-option-ui .mf-option-icon{background:var(--bg-green)!important;color:#fff!important}
.mfp-bulgaria .bg-budget-field .mf-option-group--chips .mf-option-control:checked+.mf-option-ui{border-color:var(--bg-gold)!important;background:var(--bg-gold-soft)!important;color:#9a5b16!important;box-shadow:0 0 0 1px rgba(200,133,58,.72),0 8px 18px rgba(200,133,58,.16)!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-copy{display:grid!important;gap:3px!important;min-width:0!important;flex:1 1 auto!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-label{color:var(--bg-dark)!important;font-size:14px!important;line-height:19px!important;font-weight:700!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-meta,.mfp-bulgaria .mf-option-group--cards .mf-option-desc{color:var(--bg-muted)!important;font-size:12px!important;line-height:17px!important;font-weight:500!important}
.mfp-bulgaria .mf-option-group--cards .mf-option-check{position:absolute!important;right:14px!important;top:14px!important;color:var(--bg-green)!important;font-size:20px!important;line-height:20px!important;opacity:0!important;transform:scale(.8);transition:all .16s ease}
.mfp-bulgaria .mf-option-group--cards .mf-option-control:checked+.mf-option-ui .mf-option-check{opacity:1!important;transform:scale(1)}
.mfp-bulgaria .bg-toggle .mf-option-group{display:block!important}
.mfp-bulgaria .bg-toggle .mf-option-item{display:flex!important;align-items:flex-start!important;gap:12px!important;border:1px solid var(--bg-rose)!important;border-radius:14px!important;background:var(--bg-rose-soft)!important;padding:14px!important}
.mfp-bulgaria .bg-toggle .mf-option-control{width:20px!important;height:20px!important;margin:2px 0 0!important;accent-color:var(--bg-rose)!important;flex:0 0 auto!important}
.mfp-bulgaria .bg-review{border:1px solid var(--bg-border);border-radius:14px;background:#faf8f5;padding:18px}
.mfp-bulgaria .bg-review p,.mfp-bulgaria .bg-post p{font-family:'DM Serif Display',Georgia,serif;margin:0 0 12px;color:var(--bg-dark);font-size:17px;line-height:24px}
.mfp-bulgaria .bg-review dl{display:grid;gap:0;margin:0}
.mfp-bulgaria .bg-review div{display:flex;justify-content:space-between;gap:14px;padding:8px 0;border-top:1px solid rgba(212,201,186,.55)}
.mfp-bulgaria .bg-review dt,.mfp-bulgaria .bg-review dd{margin:0;font-size:13px;line-height:18px}
.mfp-bulgaria .bg-review dt{color:var(--bg-muted);font-weight:700}
.mfp-bulgaria .bg-review dd{color:var(--bg-dark);font-weight:600;text-align:right}
.mfp-bulgaria .bg-post{display:grid;gap:10px;border:1px solid var(--bg-border);border-radius:14px;background:linear-gradient(135deg,var(--bg-green-soft),#fff);padding:18px}
.mfp-bulgaria .bg-post div{display:grid;gap:2px;padding-left:14px;border-left:3px solid var(--bg-green)}
.mfp-bulgaria .bg-post strong{color:var(--bg-dark);font-size:13px;line-height:18px}
.mfp-bulgaria .bg-post span{color:var(--bg-muted);font-size:13px;line-height:19px}
.mfp-bulgaria .bg-checks{display:grid;gap:12px}
.mfp-bulgaria .bg-checks .mf-field-label{display:none!important}
.mfp-bulgaria .bg-checks .mf-option-item{display:flex!important;align-items:flex-start!important;gap:12px!important;border:1px solid var(--bg-border)!important;border-radius:14px!important;background:#faf8f5!important;padding:13px 14px!important}
.mfp-bulgaria .bg-checks .mf-option-control{width:19px!important;height:19px!important;margin:2px 0 0!important;accent-color:var(--bg-green)!important;flex:0 0 auto!important}
.mfp-bulgaria .bg-actions{display:flex;align-items:center;justify-content:space-between;margin-top:30px;padding-top:22px;border-top:1px solid var(--bg-border)}
.mfp-bulgaria .bg-actions span{color:var(--bg-muted);font-size:12px;font-weight:600}
.mfp-bulgaria .bg-back,.mfp-bulgaria .bg-next,.mfp-bulgaria .bg-submit{border:0;border-radius:999px;padding:10px 24px;font-family:'Inter',system-ui,sans-serif;font-size:14px;line-height:20px;font-weight:700;cursor:pointer;transition:all .16s ease}
.mfp-bulgaria .bg-back{border:1px solid var(--bg-border);background:#fff;color:var(--bg-muted)}
.mfp-bulgaria .bg-back:disabled{opacity:.32;cursor:not-allowed}
.mfp-bulgaria .bg-next{background:var(--bg-rose);color:#fff}
.mfp-bulgaria .bg-submit{background:var(--bg-green);color:#fff}
.mfp-bulgaria .bg-next:hover:not(:disabled),.mfp-bulgaria .bg-submit:hover:not(:disabled){transform:translateY(-1px);filter:brightness(.96)}
.mfp-bulgaria .bg-next:disabled,.mfp-bulgaria .bg-submit:disabled{opacity:.4;cursor:not-allowed}
.mfp.mfp-bulgaria.bg-success-shell{max-width:760px!important}
.mfp-bulgaria .bg-stepper-success{margin-bottom:20px}
.mfp-bulgaria .bg-success-panel{display:grid;justify-items:center;text-align:center;padding:34px 24px 10px}
.mfp-bulgaria .bg-success-check{display:flex;align-items:center;justify-content:center;width:72px;height:72px;border-radius:999px;background:var(--bg-green);color:#fff;font-size:38px;line-height:1;margin-bottom:18px}
.mfp-bulgaria .bg-success-panel h2{font-size:38px;line-height:46px}
.mfp-bulgaria .bg-success-panel p{max-width:430px;margin:12px auto 0;color:var(--bg-muted);font-size:15px;line-height:24px}
.mfp-bulgaria .bg-success-panel strong{color:var(--bg-dark)}
.mfp-bulgaria .bg-success-panel blockquote{margin:4px 0 22px;color:var(--bg-muted);font-family:'DM Serif Display',Georgia,serif;font-size:18px;line-height:26px;font-style:normal}
.mfp-bulgaria .bg-restart{border:0;border-radius:999px;background:var(--bg-rose);color:#fff;padding:12px 30px;font-family:'Inter',system-ui,sans-serif;font-size:14px;font-weight:700;line-height:20px;cursor:pointer}
.mfp-bulgaria .bg-footer{margin:18px 0 0;text-align:center;color:var(--bg-muted);font-size:12px;line-height:18px}
.mf-form-wrapper:has(.mfp-bulgaria),.mf-form-wrapper:has(.mfp-bulgaria) .mf-form,.mf-form-wrapper:has(.mfp-bulgaria) .mf-form-inner,.mf-form-wrapper:has(.mfp-bulgaria) .mf-fields-container{overflow:visible!important}
.mf-form-wrapper:has(.bg-success-shell) .mf-success-message,.mf-form-wrapper:has(.bg-success-shell) .mf-postsubmit-pane{display:none!important}
.mfp-bulgaria .mf-form-title,.mfp-bulgaria .mf-form-description,.mfp-bulgaria .mf-success-message,.mfp-bulgaria+.mf-form-actions,.mf-form-wrapper:has(.mfp-bulgaria) .mf-form-actions{display:none!important}
.mf-form-wrapper>.mf-form-inner .mfp.mfp-bulgaria{width:100%!important;max-width:760px!important;margin:0 auto!important;padding:0!important;background:var(--bg-parch)!important}
@media(max-width:720px){.mfp.mfp-bulgaria{max-width:100%!important}.mfp-bulgaria .bg-card{border-radius:20px}.mfp-bulgaria .bg-hero{height:250px}.mfp-bulgaria .bg-hero-copy{padding:28px}.mfp-bulgaria .bg-hero-copy h1{font-size:46px}.mfp-bulgaria .bg-thumb{display:none}.mfp-bulgaria .bg-body{padding:28px 22px 30px}.mfp-bulgaria .bg-step{min-width:54px}.mfp-bulgaria .bg-step em{display:none}.mfp-bulgaria .bg-line{width:22px;margin-left:3px;margin-right:3px}.mfp-bulgaria .bg-grid-2,.mfp-bulgaria .mf-row,.mfp-bulgaria .mf-option-group--cards{grid-template-columns:1fr!important}.mfp-bulgaria .bg-actions{gap:10px}.mfp-bulgaria .bg-back,.mfp-bulgaria .bg-next,.mfp-bulgaria .bg-submit{padding:10px 18px}}
/*MF-HEROHEAD-FIX-20260626*/.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy h1{color:#fff!important;font-family:'DM Serif Display',Georgia,serif!important}.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy h1 *{color:#fff!important}.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy .bg-eyebrow,.mf-form-wrapper .mfp.mfp-bulgaria .bg-hero-copy p{color:rgba(255,255,255,.9)!important}
